const userId = $('Get Active Users').item.json.user_id;
const entries = $('Get User Entries').all().map(i => i.json);

// Group by dimension + similar text (first 60 chars)
const groups = {};
for (const entry of entries) {
  const textKey = entry.text.substring(0, 60).toLowerCase().replace(/[^a-z0-9 ]/g, '');
  const key = `${entry.dimension}__${textKey}`;

  if (!groups[key]) {
    groups[key] = {
      id: entry.id,
      dimension: entry.dimension,
      text: entry.text,
      frequency: 0,
      entries: [],
      first_seen: entry.first_seen,
      last_seen: entry.last_seen
    };
  }

  groups[key].frequency++;
  groups[key].entries.push(entry);

  if (new Date(entry.first_seen) < new Date(groups[key].first_seen)) {
    groups[key].first_seen = entry.first_seen;
  }
  if (new Date(entry.last_seen) > new Date(groups[key].last_seen)) {
    groups[key].last_seen = entry.last_seen;
  }
}

// Compute trend for each group
const midpoint = new Date(Date.now() - 45 * 24 * 60 * 60 * 1000);
const updates = Object.values(groups).map(g => {
  const recentCount = g.entries.filter(e => new Date(e.first_seen) >= midpoint).length;
  const olderCount = g.entries.length - recentCount;

  let trend = 'stable';
  if (recentCount > olderCount * 1.5) trend = 'rising';
  else if (olderCount > recentCount * 1.5) trend = 'fading';

  return {
    id: g.id,
    user_id: userId,
    dimension: g.dimension,
    text: g.text,
    frequency: g.frequency,
    trend: trend,
    first_seen: g.first_seen,
    last_seen: g.last_seen
  };
});

return updates.map(u => ({ json: u }));
